import React, { useState, useCallback, type FormEvent, type ChangeEvent } from 'react';
import { useAuth } from '../hooks/useAuth';
import { apiClient } from '../context/AuthContext';

interface EmailOtpLoginProps {
  onSuccess?: () => void;
  onError?: (error: unknown) => void;
  className?: string;
}

export function EmailOtpLogin({
  onSuccess,
  onError,
  className = '',
}: EmailOtpLoginProps) {
  const { login } = useAuth();
  const [email, setEmail] = useState('');
  const [otp, setOtp] = useState('');
  const [step, setStep] = useState<'email' | 'otp'>('email');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [expiresIn, setExpiresIn] = useState<number | null>(null);

  const handleSendOtp = useCallback(async (e: FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccessMessage(null);

    try {
      const response = await apiClient.post('/email/send-otp', { email });

      if (response.data.success) {
        setStep('otp');
        setExpiresIn(response.data.expiresIn);
        setSuccessMessage('OTP sent to your email!');
      } else {
        throw new Error('Failed to send OTP');
      }
    } catch (err: unknown) {
      let errorMessage = 'Failed to send OTP';
      if (err instanceof Error && err.message) {
        errorMessage = err.message;
      }
      if (typeof err === 'object' && err !== null && 'response' in err) {
        const response = (err as { response?: { data?: { error?: string } } }).response;
        errorMessage = response?.data?.error || errorMessage;
      }
      setError(errorMessage);
      onError?.(err);
      console.error('Send OTP error:', err);
    } finally {
      setIsLoading(false);
    }
  }, [email, onError]);

  const handleVerifyOtp = useCallback(async (e: FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      const response = await apiClient.post('/email/verify-otp', {
        email,
        otp,
      });

      if (response.data.success) {
        login(response.data.accessToken, response.data.user);
        onSuccess?.();
      } else {
        throw new Error('Invalid OTP');
      }
    } catch (err: unknown) {
      let errorMessage = 'Invalid OTP';
      if (err instanceof Error && err.message) {
        errorMessage = err.message;
      }
      if (typeof err === 'object' && err !== null && 'response' in err) {
        const response = (err as { response?: { data?: { error?: string } } }).response;
        errorMessage = response?.data?.error || errorMessage;
      }
      setError(errorMessage);
      onError?.(err);
      console.error('Verify OTP error:', err);
    } finally {
      setIsLoading(false);
    }
  }, [email, otp, login, onSuccess, onError]);

  const handleBackToEmail = useCallback(() => {
    setStep('email');
    setOtp('');
    setError(null);
    setSuccessMessage(null);
  }, []);

  return (
    <div className={`email-otp-login ${className}`}>
      {step === 'email' ? (
        <form onSubmit={handleSendOtp} className="auth-form">
          <div className="form-group">
            <label htmlFor="email" className="form-label">
              Email Address
            </label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e: ChangeEvent<HTMLInputElement>) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
              disabled={isLoading}
              className="form-input"
            />
          </div>

          {error && <div className="auth-error">{error}</div>}

          <button
            type="submit"
            disabled={isLoading || !email}
            className="auth-button"
          >
            {isLoading ? 'Sending...' : 'Send OTP'}
          </button>
        </form>
      ) : (
        <form onSubmit={handleVerifyOtp} className="auth-form">
          <div className="form-group">
            <label htmlFor="otp" className="form-label">
              Enter OTP
            </label>
            <p className="form-hint">
              We sent a 6-digit code to {email}
              {expiresIn && ` (expires in ${Math.floor(expiresIn / 60)} minutes)`}
            </p>
            <input
              id="otp"
              type="text"
              value={otp}
              onChange={(e: ChangeEvent<HTMLInputElement>) =>
                setOtp(e.target.value.replace(/\D/g, '').slice(0, 6))
              }
              placeholder="123456"
              required
              maxLength={6}
              disabled={isLoading}
              className="form-input otp-input"
              autoComplete="one-time-code"
            />
          </div>

          {successMessage && <div className="auth-success">{successMessage}</div>}
          {error && <div className="auth-error">{error}</div>}

          <button
            type="submit"
            disabled={isLoading || otp.length !== 6}
            className="auth-button"
          >
            {isLoading ? 'Verifying...' : 'Verify OTP'}
          </button>

          <button
            type="button"
            onClick={handleBackToEmail}
            disabled={isLoading}
            className="auth-button-secondary"
          >
            Change Email
          </button>
        </form>
      )}
    </div>
  );
}

